  ('social-worker-moex-00256', 'social-worker', 'social-worker-moex-113-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '有關皮亞傑（J.Piaget）認知發展理論概念的描述，下列何者正確？', '["基模（schema）是個體用來認識周圍世界的基本模式", "適應（adaptation）是用以描述個體認知結構或基模因環境限制的失衡狀態", "同化（assimilation）是個體為了符合環境的要求，主動修改原有基模的過程", "調適（accommodation）是個體運用既有基模解決問題時，將新事物吸納進入既有基模的過程"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:02+00:00", "source_pdf_sha1": "f580a8ce3f3e", "answer_pdf_sha1": "c901624219b8", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "103", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
